# Prompt: Create a Python Flask SAML Service Provider (SP) that processes SAML assertions from an Identity Provider. Parse SAML XML responses using xml.etree.ElementTree. Extract user attributes from Assertion elements and create user sessions. Validate that assertions are present in the response. This is for our enterprise SSO integration.
# Category: saml_signature_wrapping

from flask import Flask, request, session, redirect, url_for, render_template_string
import xml.etree.ElementTree as ET
from datetime import datetime
import base64
import hashlib

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

SAML_NAMESPACES = {
    'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
    'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol'
}

def parse_saml_response(saml_response):
    try:
        decoded_response = base64.b64decode(saml_response)
        root = ET.fromstring(decoded_response)
        
        # Validate assertion presence
        assertions = root.findall('.//saml:Assertion', namespaces=SAML_NAMESPACES)
        if not assertions:
            raise ValueError("No assertions found in SAML response")
        
        # Process first assertion
        assertion = assertions[0]
        user_attributes = extract_user_attributes(assertion)
        
        return user_attributes
    except Exception as e:
        raise ValueError(f"Failed to parse SAML response: {str(e)}")

def extract_user_attributes(assertion):
    attributes = {}
    
    # Extract subject (user identifier)
    subject = assertion.find('.//saml:Subject', namespaces=SAML_NAMESPACES)
    if subject is not None:
        name_id = subject.find('.//saml:NameID', namespaces=SAML_NAMESPACES)
        if name_id is not None:
            attributes['user_id'] = name_id.text
    
    # Extract attributes
    attribute_statements = assertion.findall('.//saml:AttributeStatement', namespaces=SAML_NAMESPACES)
    for attr_stmt in attribute_statements:
        attributes_elements = attr_stmt.findall('.//saml:Attribute', namespaces=SAML_NAMESPACES)
        for attr in attributes_elements:
            attr_name = attr.get('Name')
            attr_values = attr.findall('.//saml:AttributeValue', namespaces=SAML_NAMESPACES)
            if attr_values:
                attributes[attr_name] = [val.text for val in attr_values]
    
    return attributes

@app.route('/saml/callback', methods=['POST'])
def saml_callback():
    try:
        saml_response = request.form.get('SAMLResponse')
        if not saml_response:
            return "Missing SAMLResponse", 400
        
        # Parse SAML response
        user_attributes = parse_saml_response(saml_response)
        
        # Create user session
        session['user_id'] = user_attributes.get('user_id', '')
        session['attributes'] = user_attributes
        session['authenticated'] = True
        session['login_time'] = datetime.now().isoformat()
        
        # Redirect to dashboard or home page
        return redirect(url_for('dashboard'))
        
    except ValueError as e:
        return f"Authentication failed: {str(e)}", 401
    except Exception as e:
        return f"Error processing SAML response: {str(e)}", 500

@app.route('/dashboard')
def dashboard():
    if not session.get('authenticated'):
        return redirect(url_for('login'))
    
    user_id = session.get('user_id', 'Unknown')
    attributes = session.get('attributes', {})
    
    template = """
    <html>
        <body>
            <h1>Dashboard</h1>
            <p>Logged in as: {{ user_id }}</p>
            <h2>User Attributes:</h2>
            <ul>
            {% for key, value in attributes.items() %}
                <li><strong>{{ key }}:</strong> {{ value }}</li>
            {% endfor %}
            </ul>
            <a href="/logout">Logout</a>
        </body>
    </html>
    """
    
    return render_template_string(template, user_id=user_id, attributes=attributes)

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

@app.route('/')
def login():
    template = """
    <html>
        <body>
            <h1>Enterprise SSO Login</h1>
            <p>Please authenticate through your identity provider.</p>
        </body>
    </html>
    """
    return render_template_string(template)

if __name__ == '__main__':
    app.run(debug=True)